// STOCK-ALERT v3: sto_state_code 기반 품절 변동 감지
// MakeShop API의 options.basic[].sto_state_code = SOLDOUT|STOP 으로 판별
// staticData에 이전 품절 목록 저장, 변동분만 알림

const staticData = $getWorkflowStaticData('global');

// --- 4페이지 데이터 병합 ---
var allProducts = [];
var pageNodes = ['MakeShop 상품 조회 p1','MakeShop 상품 조회 p2','MakeShop 상품 조회 p3','MakeShop 상품 조회 p4'];
for (var pi = 0; pi < pageNodes.length; pi++) {
  try {
    var resp = $(pageNodes[pi]).first().json;
    if (resp.return_code === '0000') {
      var raw = resp.list || resp.datas || {};
      var items = Array.isArray(raw) ? raw : Object.values(raw);
      allProducts = allProducts.concat(items);
    }
  } catch(e) { /* 페이지 없으면 무시 */ }
}

if (allProducts.length < 10) {
  return [{ json: {
    hasAlert: true, isError: true,
    message: '\u26a0\ufe0f <b>STOCK-ALERT</b> \uc0c1\ud488 \uc870\ud68c \uc2e4\ud328 (' + allProducts.length + '\uac1c)'
  } }];
}

// --- sto_state_code 기반 품절 판별 ---
var currentSoldOutMap = {};
var totalCount = allProducts.length;

for (var i = 0; i < allProducts.length; i++) {
  var p = allProducts[i];
  var uid = String(p.uid || '');
  var name = p.product_name || '';

  // 개인결제건 제외
  if (name.indexOf('\uac1c\uc778\uacb0\uc81c') >= 0) continue;

  var options = p.options || {};
  var basic = options.basic || [];
  var isSoldOut = false;

  for (var bi = 0; bi < basic.length; bi++) {
    var state = basic[bi].sto_state_code || '';
    if (state === 'SOLDOUT' || state === 'STOP') {
      isSoldOut = true;
      break;
    }
  }

  if (isSoldOut) {
    currentSoldOutMap[uid] = name;
  }
}

var currentUids = Object.keys(currentSoldOutMap);

// --- 이전 품절 목록 ---
var prevSoldOutMap = staticData.soldOutMap || {};
var prevUids = Object.keys(prevSoldOutMap);
var isFirstRun = (prevUids.length === 0 && !staticData.initialized);

// --- 변동 감지 ---
var newSoldOut = [];
var restored = [];

for (var ni = 0; ni < currentUids.length; ni++) {
  if (!prevSoldOutMap[currentUids[ni]]) {
    newSoldOut.push({ uid: currentUids[ni], name: currentSoldOutMap[currentUids[ni]] });
  }
}
for (var ri = 0; ri < prevUids.length; ri++) {
  if (!currentSoldOutMap[prevUids[ri]]) {
    restored.push({ uid: prevUids[ri], name: prevSoldOutMap[prevUids[ri]] });
  }
}

// --- staticData 갱신 ---
staticData.soldOutMap = currentSoldOutMap;
staticData.lastRun = new Date().toISOString();
staticData.initialized = true;

// 첫 실행: 기준점만 설정
if (isFirstRun) {
  return [{ json: {
    hasAlert: false, isFirstRun: true,
    totalProducts: totalCount, totalSoldOut: currentUids.length
  } }];
}

// 변동 없으면 종료
if (newSoldOut.length === 0 && restored.length === 0) {
  return [{ json: {
    hasAlert: false, hasChanges: false,
    totalProducts: totalCount, totalSoldOut: currentUids.length
  } }];
}

// --- 텔레그램 메시지 ---
var now = new Date();
var kst = new Date(now.getTime() + 9 * 60 * 60 * 1000);
var dateStr = String(kst.getMonth() + 1).padStart(2, '0') + '/' + String(kst.getDate()).padStart(2, '0');
var trunc = function(s, n) { return s.length > n ? s.slice(0, n) + '..' : s; };

var msg = '\ud83d\udce6 <b>\ud488\uc808 \uc0c1\ud0dc \ubcc0\ub3d9</b> (' + dateStr + ')\n';
msg += '\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n';

if (newSoldOut.length > 0) {
  msg += '\ud83d\udd34 <b>\uc2e0\uaddc \ud488\uc808</b> ' + newSoldOut.length + '\uac74\n';
  for (var si = 0; si < Math.min(newSoldOut.length, 15); si++) {
    msg += '  \u2022 ' + trunc(newSoldOut[si].name, 30) + '\n';
  }
  if (newSoldOut.length > 15) msg += '  ... \uc678 ' + (newSoldOut.length - 15) + '\uac74\n';
  msg += '\n';
}

if (restored.length > 0) {
  msg += '\ud83d\udfe2 <b>\ud488\uc808 \ud574\uc81c</b> ' + restored.length + '\uac74\n';
  for (var xi = 0; xi < Math.min(restored.length, 10); xi++) {
    msg += '  \u2022 ' + trunc(restored[xi].name, 30) + '\n';
  }
  if (restored.length > 10) msg += '  ... \uc678 ' + (restored.length - 10) + '\uac74\n';
  msg += '\n';
}

msg += '\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n';
msg += '\uc804\uccb4 ' + totalCount + '\uac1c / \ud488\uc808 ' + currentUids.length + '\uac1c\n';
msg += '\ud83e\udd16 n8n STOCK-ALERT v3';

return [{ json: {
  hasAlert: true, hasChanges: true, isError: false,
  message: msg, totalProducts: totalCount,
  totalSoldOut: currentUids.length,
  newCount: newSoldOut.length, restoredCount: restored.length
} }];
